const item = $input.first().json;
if (!item.prompt) throw new Error('[SUB_Call_Claude_JSON] Missing required field: prompt');
if (!item.runId) throw new Error('[SUB_Call_Claude_JSON] Missing required field: runId');

return [{
  json: {
    runId: item.runId,
    prompt: item.prompt,
    systemPrompt: item.systemPrompt || 'You are a senior consulting business analyst. Return only valid JSON.',
    model: item.model || 'claude-sonnet-4-6',
    temperature: item.temperature ?? 0.2,
    maxTokens: item.maxTokens || 2000,
    stageName: item.stageName || 'llm_call'
  }
}];

const runId = $('Validate Input').first().json.runId;
const stageName = $('Validate Input').first().json.stageName;
const rawText = $input.first().json.text || $input.first().json.content || '';

let parsed = null;
let parseError = null;

try {
  const clean = rawText.replace(/```json\n?/g, '').replace(/```\n?/g, '').trim();
  parsed = JSON.parse(clean);
} catch(e) {
  parseError = e.message;
  console.warn(`[SUB_Call_Claude_JSON][${runId}][${stageName}] JSON parse failed: ${e.message}`);
}

return [{
  json: {
    runId,
    stageName,
    parsed,
    rawText,
    parseError,
    success: parsed !== null
  }
}];
